import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';

const UserContext = createContext();

export const UserProvider = ({ children }) => {
  const storedUser = JSON.parse(localStorage.getItem('user'));
  const storedToken = localStorage.getItem('token');
  const [user, setUserState] = useState(storedUser || null);
  const [token, setTokenState] = useState(storedToken || null);

  const saveUser = (userData, tokenData) => {
    if (userData && tokenData) {
      console.log("[saveUser] Saving user and token:", userData, tokenData);
      localStorage.setItem('user', JSON.stringify(userData));
      localStorage.setItem('token', tokenData);
      setUserState(userData);
      setTokenState(tokenData);
    }
  };

  const clearUser = () => {
    console.log("[clearUser] Clearing user and token from localStorage and state.");
    localStorage.removeItem('user');
    localStorage.removeItem('token');
    setUserState(null);
    setTokenState(null);
  };

  const checkTokenValidity = useCallback(async () => {
    const tokenToCheck = localStorage.getItem('token');
    console.log("[checkTokenValidity] Starting token check:", tokenToCheck);
    if (!tokenToCheck) return;

    try {
      const res = await fetch('http://localhost:5001/api/user/profile', {
        headers: { Authorization: `Bearer ${tokenToCheck}` },
      });

      console.log("[checkTokenValidity] Response status:", res.status);

      const data = await res.json();
      console.log("[checkTokenValidity] Response data:", data);

      if (res.status === 401 || !data.success) {
        console.warn("[checkTokenValidity] Invalid token. Clearing user.");
        clearUser();
      } else if (data.user) {
        const updatedUser = { username: data.user.username };
        console.log("[checkTokenValidity] Valid token. Updating user:", updatedUser);
        localStorage.setItem('user', JSON.stringify(updatedUser));
        setUserState(updatedUser);
        setTokenState(tokenToCheck);
      }
    } catch (err) {
      console.error("[checkTokenValidity] Exception:", err);
      clearUser();
    }
  }, []);

  useEffect(() => {
    checkTokenValidity();
  }, [checkTokenValidity]);

  return (
    <UserContext.Provider value={{
      user,
      token,
      setUser: saveUser,
      clearUser
    }}>
      {children}
    </UserContext.Provider>
  );
};

export const useUser = () => useContext(UserContext);
